.text
main:
	lui $8, 0x1001

	# carrega o primeiro cenario
	addi $4, $8, 0 
	addi $5, $8, 0
	addi $6, $0, 256
	addi $7, $0, 128
	jal desenhaImagem
	
	jal timer
	
	# carrega o segundo cenario
	addi $4, $8, 131072
	addi $5, $8, 0
	addi $6, $0, 256
	addi $7, $0, 128
	jal desenhaImagem

fim:    addi $2, $0, 10
	syscall
	
# rotina p/ desenhar
desenhaImagem:
	# $4 = endereco origem
	# $5 = endereco destino
	# $6 = largura (pixels) ou colunas
	# $7 = altura (pixels) ou linhas
	
	addi $12, $4, 0 # $12 recebe inicio do que quero desenhar
	addi $14, $5, 0 # onde vai desenhar o personagem (131072/2 + 1024/2 se for o link no centro)
	addi $15, $7, 0 # contador de linhas
forImagem: 
	beq $15, $0, fimImagem
        addi $17, $6, 0 # contador de colunas
forLinha:
        beq $17, $0, fimLinha
	# desenha a linha
	lw $16, 0($12) # le o pixel da imagem
	addi $18, $0, 0x00747474
	beq $16, $18, naoPinte # se a cor for cinza...
	lw $19, 0($14) # pega pixel do cenario pra nao perder
	sw $16, 0($14) # escreve onde vai desenhar a imagem
	sw $19, 0($12) # desenha o cenario por cima do personagem
naoPinte:
	addi $17, $17, -1
	addi $12, $12, 4
	addi $14, $14, 4
	j forLinha
fimLinha:
	# volta ao inicio da linha atual:
	sll $20, $6, 2 # largura * 4 bytes
	sub $14, $14, $20 # tira do $14 o que andou na linha
	# avanca uma linha na tela:
	addi $14, $14, 1024 # 256 pixels por linha * 4 bytes
	
	addi $15, $15, -1
	j forImagem
fimImagem:
	jr $31

# rotina timer
timer: 
	addi $25, $0, 30000
forTimer:
	beq $25, $0, fimTimer
	nop
	addi $25, $25, -1
	j forTimer
fimTimer:
	jr $31